const SKILL_DESCRIPTIONS = {"+1 Action": {"en": "The Survivor has an extra Action he may use as he pleases.", "it": "Il Sopravvissuto ha un'Azione extra da usare come preferisce."}, "+1 Damage: Melee": {"en": "The Survivor gets a +1 Damage bonus with Melee Combat Actions.", "it": "Il Sopravvissuto ottiene +1 Danno bonus con le Azioni in Mischia."}, "+1 Damage: Ranged": {"en": "The Survivor gets a +1 Damage bonus with Ranged Combat Actions.", "it": "Il Sopravvissuto ottiene +1 Danno bonus con le Azioni a Distanza."}, "+1 Damage: Magic": {"en": "The Survivor gets a +1 Damage bonus with Magic Combat Actions.", "it": "Il Sopravvissuto ottiene +1 Danno bonus con le Azioni di Magia."}, "+1 to dice roll: Combat": {"en": "The Survivor adds 1 to the result of each die he rolls on a Combat Action (Melee, Ranged or Magic). The maximum result is always 6.", "it": "Il Sopravvissuto aggiunge 1 al risultato di ogni dado che tira in un'Azione di Combattimento (in Mischia, a Distanza o di Magia). Il risultato massimo è sempre 6."}, "+1 to dice roll: Magic": {"en": "The Survivor adds 1 to the result of each die he rolls on a Magic Action. The maximum result is always 6.", "it": "Il Sopravvissuto aggiunge 1 al risultato di ogni dado che tira in un'Azione di Magia. Il risultato massimo è sempre 6."}, "+1 to dice roll: Melee": {"en": "The Survivor adds 1 to the result of each die he rolls in Melee Actions. The maximum result is always 6.", "it": "Il Sopravvissuto aggiunge 1 al risultato di ogni dado che tira in un'Azione di Mischia. Il risultato massimo è sempre 6."}, "+1 to dice roll: Ranged": {"en": "The Survivor adds 1 to the result of each die he rolls in Ranged Actions. The maximum result is always 6.", "it": "Il Sopravvissuto aggiunge 1 al risultato di ogni dado che tira in un'Azione a Distanza. Il risultato massimo è sempre 6."}, "+1 die: Combat": {"en": "The Survivor's weapons and Combat spells roll an extra die in Combat (Melee, Ranged or Magic). Dual weapons and spells gain a die each, for a total of +2 dice per Dual Combat Action.", "it": "Le armi e gli incantesimi da Combattimento del Sopravvissuto tirano un dado extra in Combattimento (in Mischia, a Distanza o di Magia). Le armi Doppie ottengono un dado ciascuna, per un totale di +2 dadi in caso di Azione Doppia di Combattimento."}, "+1 die: Magic": {"en": "The Survivor's Combat spells roll an extra die for Magic Actions. Dual Combat spells gain a die each, for a total of +2 dice per Dual Magic Action.", "it": "Gli incantesimi da Combattimento del Sopravvissuto tirano un dado extra nelle Azioni di Magia. Gli incantesimi da Combattimento Doppi ottengono un dado ciascuno per un totale di +2 dadi in caso di Azione Doppia di Magia."}, "+1 die: Melee": {"en": "The Survivor's Melee weapons roll an extra die for Melee Actions. Dual Melee weapons gain a die each, for a total of +2 dice per Dual Melee Action.", "it": "Le armi da Mischia del Sopravvissuto tirano un dado extra nelle Azioni in Mischia. Le armi Doppie da Mischia ottengono un dado ciascuna per un totale di +2 dadi in caso di Azione Doppia in Mischia."}, "+1 die: Ranged": {"en": "The Survivor's Ranged weapons roll an extra die for Ranged Actions. Dual Ranged weapons gain a die each, for a total of +2 dice per Dual Ranged Action.", "it": "Le armi a Distanza del Sopravvissuto tirano un dado extra nelle Azioni a Distanza. Le armi Doppie a Distanza ottengono un dado ciascuna, per un totale di +2 dadi in caso di Azione Doppia a Distanza."}, "+1 free Combat Action": {"en": "The Survivor has one extra free Combat Action. This Action may only be used for Melee, Ranged or Magic Actions.", "it": "Il Sopravvissuto ha un'Azione di Combattimento extra gratuita. Questa Azione può essere usata solo per le Azioni in Mischia, a Distanza o di Magia."}, "+1 free Enchantment Action": {"en": "The Survivor has one extra free Enchantment Action. This Action may only be used for Enchantment Actions.", "it": "Il Sopravvissuto ha un'Azione di Incantamento extra gratuita. Questa Azione può essere usata solo per le Azioni di Incantamento."}, "+1 free Magic Action": {"en": "The Survivor has one extra free Magic Action. This Action may only be used for Magic Actions.", "it": "Il Sopravvissuto ha un'Azione di Magia extra gratuita. Questa Azione può essere usata solo per le Azioni di Magia."}, "+1 free Melee Action": {"en": "The Survivor has one extra free Melee Action. This Action may only be used for a Melee Action.", "it": "Il Sopravvissuto ha un'Azione in Mischia extra gratuita. Questa Azione può essere usata solo per le Azioni in Mischia."}, "+1 free Move Action": {"en": "The Survivor has one extra free Move Action. This Action may only be used as a Move Action.", "it": "Il Sopravvissuto ha un'Azione di Movimento extra gratuita. Questa Azione può essere usata solo per il Movimento."}, "+1 free Ranged Action": {"en": "The Survivor has one extra free Ranged Action. This Action may only be used as a Ranged Action.", "it": "Il Sopravvissuto ha un'Azione a Distanza extra gratuita. Questa Azione può essere usata solo per le Azioni a Distanza."}, "+1 free Search Action": {"en": "The Survivor has one extra free Search Action. This Action may only be used to Search, and the Survivor can still only Search once per Turn.", "it": "Il Sopravvissuto ha un'Azione di Cercare extra gratuita. Questa Azione può essere usata solo per Cercare e il Sopravvissuto può comunque Cercare una sola volta per Turno."}, "+1 max Range": {"en": "The Survivor's Ranged weapons and Combat spells' maximum Range is increased by 1.", "it": "La Gittata massima delle armi a Distanza e degli incantesimi da Combattimento del Sopravvissuto aumenta di 1."}, "+1 Zone per Move": {"en": "The Survivor can move through one extra Zone each time he performs a Move Action. This Skill stacks with other effects benefiting Move Actions. Entering a Zone containing Zombies ends the Survivor's Move Action.", "it": "Il Sopravvissuto può muoversi attraverso una Zona extra ogni volta che effettua un'Azione di Movimento. Questa Abilità è cumulativa ad altri effetti di cui possono beneficiare le Azioni di Movimento. Entrare in una Zona che contiene degli Zombie pone termine all'Azione di Movimento del Sopravvissuto."}, "2 Zones per Move Action": {"en": "When the Survivor spends one Action to Move, he can move one or two Zones instead of one. Entering a Zone containing Zombies ends the Survivor's Move Action.", "it": "Quando il Sopravvissuto spende un'Azione di Movimento, può muoversi di una o due Zone, anziché di una. Entrare in una Zona che contiene degli Zombie pone termine all'Azione di Movimento del Sopravvissuto."}, "Ambidextrous": {"en": "The Survivor treats all Combat spells, Melee and Ranged weapons as if they had the Dual symbol.", "it": "Il Sopravvissuto considera tutte le armi da Mischia, gli incantesimi da Combattimento e le armi a Distanza come se fossero dotate del simbolo Doppia."}, "Barbarian": {"en": "When resolving a Melee Action, the Survivor may substitute the Dice number of the Melee weapon(s) he uses with the number of Zombies standing in the targeted Zone. Skills affecting the dice value, like +1 die: Melee, still apply.", "it": "Quando risolve un'Azione in Mischia, il Sopravvissuto può sostituire il valore di Dadi dell'arma o delle armi da Mischia che sta usando con il numero di Zombie che si trovano nella Zona bersaglio. Le Abilità che influenzano il numero dei dadi, come +1 dado: Mischia, si applicano normalmente."}, "Blitz": {"en": "Each time the Survivor kills the last Zombie in a Zone, he gets 1 free Move Action to use immediately.", "it": "Ogni volta che il Sopravvissuto uccide l'ultimo Zombie di una Zona, ottiene 1 Azione di Movimento gratuita da usare immediatamente."}, "Bloodlust: Combat": {"en": "Spend one Action with the Survivor: He Moves up to two Zones to a Zone containing at least one Zombie. He then gains one free Combat Action (Melee, Ranged or Magic).", "it": "Il Sopravvissuto spende un'Azione: si muove di un massimo di due Zone fino a una Zona che contiene almeno uno Zombie. Dopodiché beneficia di un'Azione di Combattimento (in Mischia, a Distanza o di Magia) gratuita, da usare immediatamente."}, "Bloodlust: Magic": {"en": "Spend one Action with the Survivor: He Moves up to two Zones to a Zone containing at least one Zombie. He then gains one free Magic Action, to use immediately.", "it": "Il Sopravvissuto spende un'Azione: si muove di un massimo di due Zone fino a una Zona che contiene almeno uno Zombie. Dopodiché beneficia di un'Azione di Magia gratuita, da usare immediatamente."}, "Bloodlust: Melee": {"en": "Spend one Action with the Survivor: He Moves up to two Zones to a Zone containing at least one Zombie. He then gains one free Melee Action, to use immediately.", "it": "Il Sopravvissuto spende un'Azione: si muove di un massimo di due Zone fino a una Zona che contiene almeno uno Zombie. Dopodiché beneficia di un'Azione in Mischia gratuita, da usare immediatamente."}, "Bloodlust: Ranged": {"en": "Spend one Action with the Survivor: He Moves up to two Zones to a Zone containing at least one Zombie. He then gains one free Ranged Action, to use immediately.", "it": "Il Sopravvissuto spende un'Azione: si muove di un massimo di due Zone fino a una Zona che contiene almeno uno Zombie. Dopodiché beneficia di un'Azione a Distanza gratuita, da usare immediatamente."}, "Born leader": {"en": "During the Survivor's Turn, he may give one free Action to another Survivor to use as he pleases. This Action must be used during the recipient's next Turn or it is lost.", "it": "Durante il proprio Turno, il Sopravvissuto può conferire un'Azione gratuita a un altro Sopravvissuto, che può usare come preferisce. Il beneficiario deve usare questa Azione nel suo prossimo Turno, altrimenti la perde."}, "Break-in": {"en": "In order to open doors, the Survivor rolls no dice and needs no equipment (but still spends an Action). He doesn't make Noise while using this Skill. The Survivor also gains one extra free Action that can only be used to open doors.", "it": "Il Sopravvissuto non ha bisogno di tirare dadi o usare Equipaggiamento per aprire le porte (ma spende comunque un'Azione). Non fa Rumore quando usa questa Abilità. Inoltre, il Sopravvissuto ha un'Azione extra gratuita che può essere usata solo per aprire porte."}, "Charge": {"en": "The Survivor can use this Skill for free, as often as he pleases, during each of his Turns: He moves up to two Zones to a Zone containing at least one Zombie. Entering a Zone containing Zombies ends the Survivor's Move Action.", "it": "Il Sopravvissuto può usare questa Abilità gratuitamente, tutte le volte che lo desidera, durante ognuno dei suoi Turni: si muove di un massimo di due Zone fino a una Zona che contiene almeno uno Zombie. Entrare in una Zona che contiene degli Zombie pone termine all'Azione di Movimento del Sopravvissuto."}, "Destiny": {"en": "The Survivor can use this Skill once per Turn when he reveals an Equipment card he drew. You can ignore and discard that card, then draw another Equipment card.", "it": "Il Sopravvissuto può usare questa Abilità una volta per Turno quando rivela una carta Equipaggiamento che ha pescato. Ignora e scarta quella carta e pesca un'altra carta Equipaggiamento."}, "Free reload": {"en": "The Survivor reloads reloadable weapons (Hand Crossbows, Orcish Crossbow, etc.) for free.", "it": "Il Sopravvissuto ricarica gratuitamente le armi ricaricabili (Balestre a Mano, Balestra Orchesca ecc.)."}, "Frenzy: Combat": {"en": "All weapons and Combat spells the Survivor carries gain +1 die per Wound the Survivor suffers. Dual weapons gain a die each, for a total of +2 dice per Wound and per Dual Combat Action.", "it": "Tutte le armi e gli incantesimi da Combattimento trasportati dal Sopravvissuto ottengono +1 dado per ogni Ferita subita dal Sopravvissuto. Le armi Doppie ottengono un dado ciascuna, per un totale di +2 dadi per Ferita e per ogni Azione Doppia di Combattimento."}, "Frenzy: Magic": {"en": "Combat spells the Survivor carries gain +1 die per Wound the Survivor suffers. Dual Combat spells gain a die each, for a total of +2 dice per Wound and per Dual Magic Action.", "it": "Gli incantesimi da Combattimento trasportati dal Sopravvissuto ottengono +1 dado per ogni Ferita subita. Gli incantesimi Doppi ottengono un dado ciascuno, per un totale di +2 dadi per Ferita e per ogni Azione Doppia di Magia."}, "Frenzy: Melee": {"en": "Melee weapons the Survivor carries gain +1 die per Wound the Survivor suffers. Dual Melee weapons gain a die each, for a total of +2 dice per Wound and per Dual Melee Action.", "it": "Le armi da Mischia trasportate dal Sopravvissuto ottengono +1 dado per ogni Ferita subita. Le armi Doppie ottengono un dado ciascuna, per un totale di +2 dadi per Ferita e per ogni Azione Doppia in Mischia."}, "Frenzy: Ranged": {"en": "Ranged weapons the Survivor carries gain +1 die per Wound the Survivor suffers. Dual Ranged weapons gain a die each, for a total of +2 dice per Wound and per Dual Ranged Action.", "it": "Le armi a Distanza trasportate dal Sopravvissuto ottengono +1 dado per ogni Ferita subita. Le armi Doppie ottengono un dado ciascuna, per un totale di +2 dadi per Ferita e per ogni Azione Doppia a Distanza."}, "Hit & run": {"en": "The Survivor can use this Skill for free, just after resolving a Magic, Melee or Ranged Action resulting in at least one Zombie kill. He can then resolve a free Move Action. He does not spend extra Actions to perform this free Move Action if Zombies are in his Zone.", "it": "Il Sopravvissuto può usare questa Abilità gratuitamente, subito dopo avere risolto un'Azione in Mischia, a Distanza o di Magia che abbia ucciso almeno uno Zombie. Può allora risolvere un'Azione di Movimento gratuita. Non spende Azioni extra se ci sono Zombie nella sua Zona."}, "Hold your nose": {"en": "This Skill can be used once per Turn. The Survivor gets a free Search Action in the Zone if he has eliminated a Zombie (even in a Vault or street Zone) the same Game Round. The Survivor can still only Search once per Turn.", "it": "Questa Abilità può essere usata una volta per Turno. Il Sopravvissuto ottiene un'Azione di Cercare gratuita nella Zona, se ha eliminato uno Zombie in quello stesso Round di Gioco. Il Sopravvissuto può comunque Cercare una sola volta per Turno."}, "Iron hide": {"en": "The Survivor can make Armor rolls with a 5+ Armor value, even when he does not wear an armor on his Body slot. Wearing an armor, the Survivor adds 1 to the result of each die he rolls for Armor rolls. The maximum result is always 6.", "it": "Il Sopravvissuto può effettuare tiri Armatura con un valore di Armatura 5+ anche quando non indossa un'armatura sul suo slot Corpo. Indossando un'armatura, il Sopravvissuto aggiunge 1 al risultato di ogni dado nei tiri Armatura. Il risultato massimo è sempre 6."}, "Iron rain": {"en": "When resolving a Ranged Action, the Survivor may substitute the Dice number of the Ranged weapon(s) he uses with the number of Zombies standing in the targeted Zone. Skills affecting the dice value, like +1 die: Ranged, still apply.", "it": "Quando risolve un'Azione a Distanza, il Sopravvissuto può sostituire il valore di Dadi dell'arma o delle armi a Distanza che usa con il numero degli Zombie che si trovano nella Zona bersaglio. Le Abilità che influenzano il numero dei dadi, come +1 dado: Distanza, si applicano normalmente."}, "Is that all you've got?": {"en": "You can use this Skill any time the Survivor is about to get Wounds. Discard one Equipment card in your Survivor's inventory for each Wound he's about to receive. Negate a Wound per discarded Equipment card.", "it": "Un Sopravvissuto può usare questa Abilità ogni volta che sta per ricevere delle Ferite. Scarta una carta Equipaggiamento contenuta nel suo inventario per ogni Ferita che sta per ricevere, negando una Ferita per ogni carta Equipaggiamento scartata."}, "Jump": {"en": "The Survivor can use this Skill once during each Activation. He spends one Action: He moves two Zones into a Zone to which he has Line of Sight. Movement related Skills are ignored, but Movement penalties still apply. Ignore everything in the intervening Zone.", "it": "Il Sopravvissuto può usare questa Abilità una volta durante ogni Attivazione. Spendendo un'Azione, si muove di due Zone fino a una Zona verso cui dispone di Linea di Vista. Le Abilità correlate al Movimento sono ignorate, mentre le penalità al Movimento vanno applicate. Si ignora tutto ciò che si trova nella Zona frapposta."}, "Lifesaver": {"en": "The Survivor can use this Skill, for free, once during each of his Turns. Select a Zone at Range 1 containing at least one Zombie. Choose Survivors in the selected Zone to be dragged to your Survivor's Zone without penalty. A Survivor can decline the rescue. Both Zones need to share a clear path.", "it": "Il Sopravvissuto può usare questa Abilità gratuitamente, una volta durante ogni suo Turno. Scegliete una Zona a Gittata 1 che contenga almeno uno Zombie. Scegliete i Sopravvissuti situati nella Zona selezionata che saranno trascinati nella Zona del Sopravvissuto salvatore senza penalità. Entrambe le Zone devono condividere un percorso sgombro."}, "Lock it down": {"en": "At the cost of one Action, the Survivor can close an open door in his Zone. Opening or destroying it again later does not trigger a new Zombie Spawn.", "it": "Al costo di un'Azione, il Sopravvissuto può chiudere una porta aperta nella sua Zona. Se successivamente viene riaperta o sfondata, non attiva una nuova Generazione di Zombie."}, "Loud": {"en": "Once during each of his Turns, the Survivor can make a huge amount of noise! Until this Survivor's next Turn, the Zone he used this Skill in is considered to have the highest number of Noise tokens on the entire board.", "it": "Una volta per ogni suo Turno, il Sopravvissuto può produrre un grande ammontare di rumore! Fino al suo Turno successivo, la Zona in cui ha usato questa Abilità è considerata dotata del più alto numero di segnalini Rumore in tutta la mappa."}, "Low profile": {"en": "The Survivor can't get hit by Survivors' Magic and Ranged Actions. Ignore him when casting a Combat spell or shooting in the Zone he stands in. Game effects that kill everything in the targeted Zone still kill him.", "it": "Il Sopravvissuto non può essere bersagliato dalle Azioni a Distanza e dalle Azioni di Magia degli altri Sopravvissuti. Viene ignorato quando qualcuno tira o lancia un incantesimo da Combattimento nella sua Zona. Gli effetti che uccidono ogni cosa nella Zona bersaglio lo uccidono comunque."}, "Lucky": {"en": "The Survivor can re-roll once all the dice for each Action (or Armor roll) he takes. The new result takes the place of the previous one. This Skill stacks with other Skills and Equipment that allows re-rolls.", "it": "Il Sopravvissuto può ripetere una volta il tiro di tutti i dadi di ogni Azione (o tiro Armatura) che effettua. Il nuovo risultato sostituisce il precedente. Questa Abilità è cumulativa agli effetti delle altre Abilità e all'Equipaggiamento che consente di ripetere il tiro."}, "Mana rain": {"en": "When resolving a Magic Action, the Survivor may substitute the Dice number of the Combat spell(s) he uses with the number of Zombies standing in the targeted Zone. Skills affecting the dice value, like +1 die: Magic, still apply.", "it": "Quando risolve un'Azione di Magia, il Sopravvissuto può sostituire il valore di Dadi dell'incantesimo o degli incantesimi da Combattimento che usa con il numero di Zombie che si trovano nella Zona bersaglio. Le abilità che influenzano il numero dei dadi, come +1 dado: Magia, si applicano normalmente."}, "Marksman": {"en": "The Survivor may freely choose the targets of all his Magic and Ranged Actions. Misses don't hit Survivors.", "it": "Il Sopravvissuto può scegliere liberamente i bersagli di tutte le sue Azioni di Magia e a Distanza. Gli insuccessi non colpiscono i Sopravvissuti."}, "Matching set!": {"en": "When a Survivor performs a Search Action and draws an Equipment card with the Dual symbol, he can immediately take a second card of the same type from the Equipment deck. Shuffle the deck afterward.", "it": "Quando un Sopravvissuto effettua un'Azione di Cercare e pesca una carta arma con il simbolo Doppia, può immediatamente prendere una seconda carta dello stesso tipo dal mazzo dell'Equipaggiamento. Dopodiché rimescola il mazzo."}, "Point-blank": {"en": "The Survivor can resolve Ranged and Magic Actions in his own Zone, no matter the minimum Range. When resolving a Magic or Ranged Action at Range 0, the Survivor freely chooses the targets and can kill any type of Zombies. Misses don't hit Survivors.", "it": "Il Sopravvissuto può risolvere le Azioni a Distanza e le Azioni di Magia nella sua stessa Zona, a prescindere dalla Gittata minima. Quando risolve un'Azione a Gittata 0, il Sopravvissuto sceglie liberamente i bersagli e può uccidere qualsiasi tipo di Zombie. Gli insuccessi non colpiscono i Sopravvissuti."}, "Reaper: Combat": {"en": "Use this Skill when assigning hits while resolving a Combat Action (Melee, Ranged or Magic). One of these hits can freely kill an additional identical Zombie in the same Zone. Only a single additional Zombie can be killed per Action. The Survivor gains the experience for the additional Zombie.", "it": "Questa Abilità si usa al momento di assegnare i colpi durante la risoluzione di un'Azione di Combattimento (in Mischia, a Distanza o di Magia). Uno di questi colpi può gratuitamente uccidere uno Zombie identico aggiuntivo situato nella stessa Zona. Soltanto un singolo Zombie aggiuntivo per Azione può essere ucciso usando questa Abilità."}, "Reaper: Magic": {"en": "Use this Skill when assigning hits while resolving a Magic Action. One of these hits can freely kill an additional identical Zombie in the same Zone. Only a single additional Zombie can be killed per Action. The Survivor gains the experience for the additional Zombie.", "it": "Questa Abilità si usa al momento di assegnare i colpi durante la risoluzione di un'Azione di Magia. Uno di questi colpi può gratuitamente uccidere uno Zombie identico aggiuntivo situato nella stessa Zona. Soltanto un singolo Zombie aggiuntivo per Azione."}, "Reaper: Melee": {"en": "Use this Skill when assigning hits while resolving a Melee Action. One of these hits can freely kill an additional identical Zombie in the same Zone. Only a single additional Zombie can be killed per Action. The Survivor gains the experience for the additional Zombie.", "it": "Questa Abilità si usa al momento di assegnare i colpi durante la risoluzione di un'Azione in Mischia. Uno di questi colpi può gratuitamente uccidere uno Zombie identico aggiuntivo situato nella stessa Zona. Soltanto un singolo Zombie aggiuntivo per Azione."}, "Reaper: Ranged": {"en": "Use this Skill when assigning hits while resolving a Ranged Action. One of these hits can freely kill an additional identical Zombie in the same Zone. Only a single additional Zombie can be killed per Action. The Survivor gains the experience for the additional Zombie.", "it": "Questa Abilità si usa al momento di assegnare i colpi durante la risoluzione di un'Azione a Distanza. Uno di questi colpi può gratuitamente uccidere uno Zombie identico aggiuntivo situato nella stessa Zona. Soltanto un singolo Zombie aggiuntivo per Azione."}, "Regeneration": {"en": "At the end of each Game Round, remove all Wounds the Survivor received. Regeneration doesn't work if the Survivor has been eliminated.", "it": "Alla fine di ogni Round di Gioco, il Sopravvissuto rimuove tutte le Ferite che ha ricevuto. Rigenerazione non funziona se il Sopravvissuto è stato eliminato."}, "Roll 6: +1 die Combat": {"en": "You may roll an additional die for each '6' rolled on any Combat Action (Melee, Ranged or Magic). Keep on rolling additional dice as long as you keep getting '6'. Game effects that allow re-rolls must be used before rolling any additional dice for this Skill.", "it": "Il Sopravvissuto può tirare un dado aggiuntivo per ogni '6' ottenuto in qualsiasi Azione di Combattimento (in Mischia, a Distanza o di Magia). Continua a tirare dadi aggiuntivi fintanto che ottiene dei '6'. Gli effetti di gioco che consentono di ripetere il tiro devono essere applicati prima di tirare qualsiasi dado aggiuntivo."}, "Roll 6: +1 die Magic": {"en": "You may roll an additional die for each '6' rolled on a Magic Action. Keep on rolling additional dice as long as you keep getting '6'. Game effects that allow re-rolls must be used before rolling any additional dice for this Skill.", "it": "Il Sopravvissuto può tirare un dado aggiuntivo per ogni '6' ottenuto in qualsiasi Azione di Magia. Continua a tirare dadi aggiuntivi fintanto che ottiene dei '6'. Gli effetti di gioco che consentono di ripetere il tiro devono essere applicati prima di tirare qualsiasi dado aggiuntivo."}, "Roll 6: +1 die Melee": {"en": "You may roll an additional die for each '6' rolled on a Melee Action. Keep on rolling additional dice as long as you keep getting '6'. Game effects that allow re-rolls must be used before rolling any additional dice for this Skill.", "it": "Il Sopravvissuto può tirare un dado aggiuntivo per ogni '6' ottenuto in qualsiasi Azione in Mischia. Continua a tirare dadi aggiuntivi fintanto che ottiene dei '6'. Gli effetti di gioco che consentono di ripetere il tiro devono essere applicati prima di tirare qualsiasi dado aggiuntivo."}, "Roll 6: +1 die Ranged": {"en": "You may roll an additional die for each '6' rolled on a Ranged Action. Keep on rolling additional dice as long as you keep getting '6'. Game effects that allow re-rolls must be used before rolling any additional dice for this Skill.", "it": "Il Sopravvissuto può tirare un dado aggiuntivo per ogni '6' ottenuto in qualsiasi Azione a Distanza. Continua a tirare dadi aggiuntivi fintanto che ottiene dei '6'. Gli effetti di gioco che consentono di ripetere il tiro devono essere applicati prima di tirare qualsiasi dado aggiuntivo."}, "Rotten": {"en": "At the end of his Turn, if the Survivor has not resolved a Combat Action and not produced a Noise token, place a Rotten token next to his base. As long as he has this token, he is totally ignored by all Zombies. He loses the Rotten token if he resolves any Combat Action or makes noise.", "it": "Alla fine del suo Turno, se il Sopravvissuto non ha effettuato un'Azione di Combattimento e non ha prodotto un segnalino Rumore, riceve un segnalino Putrefazione. Fintanto che possiede questo segnalino, viene totalmente ignorato da qualsiasi tipo di Zombie. Perde il segnalino se risolve una qualsiasi Azione di Combattimento o se produce Rumore."}, "Scavenger": {"en": "The Survivor can Search in any Zone. This includes street Zones, Vault Zones, etc.", "it": "Il Sopravvissuto può Cercare in qualsiasi Zona. Questo include le Zone di strada, le Zone delle Cripte ecc."}, "Search: +1 card": {"en": "Draw an extra card when Searching with the Survivor.", "it": "Quando il Sopravvissuto effettua l'Azione di Cercare, pesca una carta extra."}, "Shove": {"en": "The Survivor can use this Skill, for free, once during each of his Turns. Select a Zone at Range 1. All Zombies standing in your Survivor's Zone are pushed to the selected Zone. Both Zones need to share a clear path. A Zombie can't cross closed doors or walls.", "it": "Il Sopravvissuto può usare questa Abilità gratuitamente, una volta durante ogni suo Turno. Scegliete una Zona a Gittata 1. Tutti gli Zombie che si trovano nella Zona del Sopravvissuto vengono spinti nella Zona scelta. Entrambe le Zone devono condividere un percorso sgombro. Uno Zombie non può attraversare le porte chiuse o i muri."}, "Slippery": {"en": "The Survivor does not spend extra Actions when he performs a Move Action out of a Zone containing Zombies. Entering a Zone containing Zombies ends the Survivor's Move Action.", "it": "Il Sopravvissuto non spende Azioni extra quando effettua un'Azione di Movimento attraverso una Zona in cui ci sono degli Zombie. Entrare in una Zona che contiene degli Zombie pone termine all'Azione di Movimento del Sopravvissuto."}, "Spellbook": {"en": "All Combat spells and Enchantments in the Survivor's Inventory are considered equipped in Hand. The Survivor can effectively have several Combat spells and Enchantments equipped in Hand. He can only use two identical dual Combat Spells at any given time.", "it": "Tutti gli incantesimi da Combattimento e gli Incantamenti nell'inventario del Sopravvissuto sono considerati impugnati in Mano. Con questa Abilità, un Sopravvissuto può a tutti gli effetti essere considerato dotato di vari incantesimi da Combattimento e Incantamenti impugnati in Mano. Può usare solo due incantesimi da Combattimento Doppi in un determinato momento."}, "Spellcaster": {"en": "The Survivor has one extra free Action. This Action may only be used for a Magic Action or an Enchantment Action.", "it": "Il Sopravvissuto ha un'Azione gratuita extra. Questa azione può essere usata solo per un'Azione di Magia o un'Azione di Incantamento."}, "Sprint": {"en": "The Survivor can use this Skill once during each of his Turns. Spend one Move Action: He may move two or three Zones instead of one. Entering a Zone containing Zombies ends the Survivor's Move Action.", "it": "Il Sopravvissuto può usare questa Abilità una volta durante ogni suo Turno. Spendendo una delle sue Azioni di Movimento, può muoversi di due o tre Zone anziché di una. Entrare in una Zona che contiene degli Zombie pone termine all'Azione di Movimento del Sopravvissuto."}, "Super strength": {"en": "Consider the Damage value of Melee weapons used by the Survivor to be 3.", "it": "Il valore di Danno delle armi da Mischia usate dal Sopravvissuto è pari a 3."}, "Steady hand": {"en": "The Survivor can ignore other Survivors of his choosing when missing with a Magic or Ranged Action. The Skill does not apply to game effects killing everything in the targeted Zone.", "it": "Il Sopravvissuto può ignorare gli altri Sopravvissuti a sua scelta quando ottiene degli insuccessi con un'Azione a Distanza o di Magia. Questa Abilità non si applica agli effetti di gioco che uccidono ogni cosa nella Zona bersaglio."}, "Swordmaster": {"en": "The Survivor treats all Melee weapons as if they had the Dual symbol.", "it": "Il Sopravvissuto considera tutte le armi da Mischia come se fossero dotate del simbolo Doppia."}, "Tactician": {"en": "The Survivor's Turn can be resolved anytime during the Players' Phase, before or after any other Survivor's Turn. If several Survivors benefit from this Skill at the same time, choose their Turn order.", "it": "Il Turno del Sopravvissuto può essere risolto in qualsiasi momento durante la Fase dei Giocatori, prima o dopo il Turno di qualsiasi altro Sopravvissuto. Se più Sopravvissuti beneficiano di questa Abilità allo stesso tempo, scelgono il loro ordine di Turno."}, "Taunt": {"en": "The Survivor can use this Skill, for free, once during each of his Turns. Select a Zone your Survivor can see. All Zombies standing in the selected Zone immediately gain an extra Activation and try to reach the taunting Survivor by any means. Taunted Zombies ignore all other Survivors.", "it": "Il Sopravvissuto può usare questa Abilità gratuitamente, una volta durante ogni suo Turno. Scegliete una Zona che il Sopravvissuto è in grado di vedere. Tutti gli Zombie situati nella Zona selezionata ottengono immediatamente un'Attivazione Extra e cercano di raggiungere il Sopravvissuto provocatore con ogni mezzo. Gli Zombie provocati ignorano tutti gli altri Sopravvissuti."}, "Tough": {"en": "The Survivor ignores the first Wound he receives from a single Zombie every Zombies' Phase.", "it": "Il Sopravvissuto ignora la prima Ferita che riceve da un singolo Zombie in ogni Fase degli Zombie."}, "Trick shot": {"en": "When the Survivor is equipped with Dual Combat spells or Ranged weapons, he can aim at different Zones with each spell/weapon in the same Action.", "it": "Quando il Sopravvissuto impugna armi Doppie a Distanza o incantesimi Doppi da Combattimento, può mirare sui bersagli in Zone diverse con ogni arma/incantesimo nel corso della stessa Azione."}, "Zombie link": {"en": "The Survivor plays an extra Turn each time an Extra Activation card is drawn from the Zombie pile. He plays before the extra-activated Zombies. If several Survivors benefit from this Skill at the same time, choose their Turn order.", "it": "Il Sopravvissuto gioca un Turno extra ogni volta che una carta Attivazione Extra viene pescata dal mazzo degli Zombie. Gioca questo Turno prima degli Zombie che beneficiano dell'Attivazione Extra. Se più Sopravvissuti beneficiano di questa Abilità allo stesso tempo, scelgono il loro ordine di Turno."}};
const ZOMBIES = [{"id":"ZW001","name":"Walker","set":"Black Plague","tipo":"Walker","priorita":4,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":null,"avatar":"img/avatar_ZW001.jpg","card":"img/card_ZW001.webp"},{"id":"ZF001","name":"Fatty","set":"Black Plague","tipo":"Fatty","priorita":5,"azioni":1,"danni":1,"resistenza":2,"esperienza":1,"regole_speciali":null,"avatar":"img/avatar_ZF001.jpg","card":"img/card_ZF001.webp"},{"id":"ZA001","name":"Abomination","set":"Black Plague","tipo":"Abomination","priorita":5,"azioni":1,"danni":1,"resistenza":3,"esperienza":5,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura.","avatar":"img/avatar_ZA001.jpg","card":"img/card_ZA001.webp"},{"id":"ZA002","name":"Wolfbomination","set":"Wulfsburg","tipo":"Abomination","priorita":5,"azioni":3,"danni":1,"resistenza":3,"esperienza":5,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura.","avatar":"img/avatar_ZA002.jpg","card":"img/card_ZA002.webp"},{"id":"ZA003","name":"Abominalpha","set":"Huntsman Pack","tipo":"Abomination","priorita":5,"azioni":3,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura. Finché un Abominalpha è presente sul tabellone, quando vengono generati dei Runners (di qualsiasi tipo), genera invece la stessa quantità di Zombie Wolfz.","avatar":"img/avatar_ZA003.png","card":"img/card_ZA003.webp"},{"id":"ZA004","name":"Abominarat","set":"Huntsman Pack","tipo":"Abomination","priorita":5,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura. Quando viene pescata la sua carta Zombie, un Abominarat compare a 1 Zona di distanza dalla Zona più rumorosa sul tabellone, con un passaggio aperto che collega entrambe le Zone. Se più Zone sono idonee, o non è disponibile alcun passaggio aperto, i giocatori scelgono.","avatar":"img/avatar_ZA004.png","card":"img/card_ZA004.webp"},{"id":"ZA005","name":"Abominotaur","set":"Add-Ons","tipo":"Abomination","priorita":5,"azioni":1,"danni":2,"resistenza":3,"esperienza":5,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura. Può sfondare porte chiuse e muri durante il movimento verso la Zona bersaglio (esclusi Vault e bastioni): posiziona un segnalino Muro Rotto tra le due Zone e rimuovi l'eventuale segnalino porta chiusa. Il Muro Rotto è considerato una porta aperta e può generare una Spawn. Ridefinisci i percorsi degli Zombie dopo la demolizione.","avatar":"img/avatar_ZA005.png","card":"img/card_ZA005.webp"},{"id":"ZA006","name":"Abominatroll","set":"Add-Ons","tipo":"Abomination","priorita":5,"azioni":"1*","danni":1,"resistenza":"3*","esperienza":5,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura. Ha 3 Azioni invece di 1 quando si attiva con Linea di Vista su uno o più Sopravvissuti, con attivazione multipla come i Runner/Wolfz. Può essere eliminato solo con il Fuoco di Drago (inclusi i suoi effetti).","avatar":"img/avatar_ZA006.png","card":"img/card_ZA006.webp"},{"id":"ZA007","name":"Ablobination","set":"Add-Ons","tipo":"Abomination","priorita":5,"azioni":1,"danni":"1*","resistenza":3,"esperienza":5,"regole_speciali":"Le ferite inferte non possono essere prevenute dai tiri Armatura. Attacca ogni volta che si attiva con Linea di Vista su uno o più Sopravvissuti a Gittata 0-1, colpendo tutti i Sopravvissuti in tutte le Zone a Gittata 0-1 su cui ha Linea di Vista. Gli ostacoli che bloccano il movimento (come i bastioni) bloccano anche questo attacco.","avatar":"img/avatar_ZA007.png","card":"img/card_ZA007.webp"},{"id":"ZR001","name":"Runner","set":"Black Plague","tipo":"Runner","priorita":6,"azioni":2,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":null,"avatar":"img/avatar_ZR001.jpg","card":"img/card_ZR001.webp"},{"id":"ZL001","name":"Zombie Wolfz","set":"Wulfsburg","tipo":"Wolfz","priorita":7,"azioni":3,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":null,"avatar":"img/avatar_ZL001.png","card":"img/card_ZL001.webp"},{"id":"ZN001","name":"Necromancer","set":"Black Plague","tipo":"Necromancer","priorita":8,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"All'apparizione crea una Zona di Generazione aggiuntiva nella sua Zona d'entrata, che genera subito Zombie. Ogni carta Necromante pescata assegna un'Attivazione Extra a tutti i Necromanti in gioco. Si muove verso la Zona di Generazione più vicina (non quella d'entrata a meno che non ce ne siano altre; a parità di distanza puoi sceglierne una) ignorando i Sopravvissuti, a meno che non si trovi nella loro stessa Zona. Se viene ucciso, rimuovi un qualsiasi segnalino Generazione a tua scelta. Se fugge e sul tabellone ci sono 6 o più segnalini Generazione, i giocatori perdono immediatamente.","avatar":"img/avatar_ZN001.jpg","card":"img/card_ZN001.webp"},{"id":"ZN002","name":"Evil Troy","set":"Huntsman Pack","tipo":"Necromancer","priorita":8,"azioni":1,"danni":1,"resistenza":3,"esperienza":5,"regole_speciali":"Utilizza le regole del Necromancer. Quando viene ucciso, rimettilo nella sua Zona di Generazione e non rimuovere un segnalino Generazione, a meno che non sia stato usato un Attacco con Danno 3 (o superiore) o Fuoco di Drago.","avatar":"img/avatar_ZN002.png","card":"img/card_ZN002.webp"},{"id":"ZN003","name":"Grin","set":"Huntsman Pack","tipo":"Necromancer","priorita":8,"azioni":1,"danni":1,"resistenza":3,"esperienza":5,"regole_speciali":"Utilizza le regole del Necromancer. Quando si muove, si sposta in due zone anziché in una.","avatar":"img/avatar_ZN003.png","card":"img/card_ZN003.webp"},{"id":"ZN004","name":"Queen Medea","set":"Huntsman Pack","tipo":"Necromancer","priorita":8,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Utilizza le regole del Necromancer. Non può essere eliminata se ci sono altri zombi nella sua zona. Il Fuoco di Drago la elimina normalmente.","avatar":"img/avatar_ZN004.png","card":"img/card_ZN004.webp"},{"id":"ZW002","name":"Deadeye Walker","set":"Add-Ons","tipo":"Walker","priorita":4,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Attacca ogni volta che si attiva con Linea di Vista su uno o più Sopravvissuti a Gittata 0-3, eseguendo un attacco standard sulla Zona bersaglio. Se più Zone sono eleggibili sceglie secondo queste priorità: 1. La Zona con più Sopravvissuti. 2. La Zona più rumorosa. 3. A parità, i giocatori scelgono.","avatar":"img/avatar_ZW002.png","card":"img/card_ZW002.webp"},{"id":"ZW003","name":"NPC Walker","set":"Add-Ons","tipo":"Walker","priorita":4,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Walker standard (attivazioni extra comprese) con status NPC. A inizio partita mescola le carte NPC nel mazzo Zombi standard (quando pescata prendi gli NPC casualmente, se terminati prendi i Walker standard), poi crea un mazzo con tutte le carte Artefatto della Cripta. Ogni volta che un NPC Walker viene eliminato, il giocatore può posizionarne la miniatura sulla Scheda ID del Sopravvissuto attaccante (ottenendo comunque l'XP). Le miniature NPC possono essere restituite alla riserva in qualsiasi momento. Cinque NPC Walker di sculture diverse si scambiano con una carta Artefatto della Cripta casuale. Gli NPC perdono il loro status se rimpiazzati da Necromanti o Abomini.","avatar":"img/avatar_ZW003.png","card":"img/card_ZW003.webp"},{"id":"ZC001","name":"Murder of Crowz","set":"Add-Ons","tipo":"Crowz","priorita":3,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Si muovono fino a 3 Zone per raggiungere la Zona bersaglio, stabilita prima del movimento ignorando i Vault. Non cambiano rotta se appare un nuovo bersaglio lungo il percorso. In caso di divisione del gruppo, questa avviene solo alla scelta della Zona bersaglio, non durante il movimento. Ignorano tutti gli ostacoli al movimento (porte chiuse, bastioni, muri) e gli effetti che impedirebbero loro di restare in una Zona.","avatar":"img/avatar_ZC001.png","card":"img/card_ZC001.webp"},{"id":"ZM001","name":"Swarm of Ratz","set":"No Rest for the Wicked","tipo":"Ratz","priorita":3,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Ogni carta Sciame di Ratti pescata assegna un'Attivazione Extra a tutti gli Sciami di Ratti in gioco. Hanno 1 sola Azione per Attivazione (muoversi o attaccare): si muovono fino a 2 Zone per raggiungere la Zona bersaglio, stabilita prima del movimento (non cambiano rotta se appare un nuovo bersaglio lungo il percorso). Ignorano tutti gli ostacoli al movimento eccetto porte chiuse e muri.","avatar":"img/avatar_ZM001.jpg","card":"img/card_ZM001.webp"},{"id":"ZN005","name":"Ostokar","set":"Special Guest","autore":"Naiade","tipo":"Necromancer","priorita":8,"azioni":1,"danni":1,"resistenza":1,"esperienza":1,"regole_speciali":"Utilizza le regole del Necromancer. Ogni volta che ottiene un'Attivazione Extra, anche tutti gli Zombie nella sua Zona ottengono un'Attivazione Extra.","avatar":"img/avatar_ZN005.png","card":"img/card_ZN005.webp"}];
